import{_ as t,o as s,c as a,ae as i}from"./chunks/framework.CHRjkDA5.js";const k=JSON.parse('{"title":"Rendering","description":"Learn how Elena detects changes, batches updates, and efficiently re-renders components.","frontmatter":{"title":"Rendering","description":"Learn how Elena detects changes, batches updates, and efficiently re-renders components.","head":[["meta",{"property":"og:title","content":"Rendering | Elena"}],["meta",{"property":"og:description","content":"Learn how Elena detects changes, batches updates, and efficiently re-renders components."}],["meta",{"name":"twitter:description","content":"Learn how Elena detects changes, batches updates, and efficiently re-renders components."}]]},"headers":[{"level":2,"title":"How the DOM is updated","slug":"how-the-dom-is-updated","link":"#how-the-dom-is-updated","children":[]},{"level":2,"title":"What triggers an update","slug":"what-triggers-an-update","link":"#what-triggers-an-update","children":[]},{"level":2,"title":"How prop changes are detected","slug":"how-prop-changes-are-detected","link":"#how-prop-changes-are-detected","children":[{"level":3,"title":"Reflected vs non-reflected props","slug":"reflected-vs-non-reflected-props","link":"#reflected-vs-non-reflected-props","children":[]}]},{"level":2,"title":"Batched updates","slug":"batched-updates","link":"#batched-updates","children":[]},{"level":2,"title":"What Elena cannot detect","slug":"what-elena-cannot-detect","link":"#what-elena-cannot-detect","children":[]},{"level":2,"title":"The update cycle","slug":"the-update-cycle","link":"#the-update-cycle","children":[]},{"level":2,"title":"Waiting for a render","slug":"waiting-for-a-render","link":"#waiting-for-a-render","children":[]},{"level":2,"title":"Before the first render","slug":"before-the-first-render","link":"#before-the-first-render","children":[]}],"relativePath":"components/rendering.md","filePath":"components/rendering.md","lastUpdated":1775370521000}'),n={name:"components/rendering.md"};function h(r,e,l,p,d,o){return s(),a("div",null,[...e[0]||(e[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /pr-preview/pr-15/components/rendering.md for this page in Markdown format</div><h1 id="rendering" tabindex="-1">Rendering <a class="header-anchor" href="#rendering" aria-label="Permalink to &quot;Rendering&quot;">​</a></h1><p>Elena renders a web component once when it connects to the page. After that, any change to a <a href="/pr-preview/pr-15/components/props">reactive property</a> triggers an update. Elena performs updates asynchronously so property changes are batched: if there are multiple changes, they are combined into a single render.</p><h2 id="how-the-dom-is-updated" tabindex="-1">How the DOM is updated <a class="header-anchor" href="#how-the-dom-is-updated" aria-label="Permalink to &quot;How the DOM is updated&quot;">​</a></h2><p>When Elena updates, it calls <code>render()</code> and compares the result to what is currently in the DOM. It uses two strategies depending on what changed:</p><ul><li><strong>Patch:</strong> if the template shape is the same, Elena patches only the text nodes and attribute values that changed. The DOM structure stays intact, preserving element identity, focus state, and scroll position.</li><li><strong>Morph:</strong> if the template shape changed, Elena rebuilds the affected portion of the DOM and morphs it into place, updating attributes and text in existing nodes where possible.</li></ul><h2 id="what-triggers-an-update" tabindex="-1">What triggers an update <a class="header-anchor" href="#what-triggers-an-update" aria-label="Permalink to &quot;What triggers an update&quot;">​</a></h2><p>Elena schedules an update when any of these change:</p><ul><li><strong>A prop value</strong> listed in <code>static props</code> is set to a new value</li><li><strong>The <code>text</code> property</strong> is updated</li><li><strong>An observed attribute</strong> changes on the host element</li><li><strong><code>requestUpdate()</code></strong> is called manually</li></ul><p>All four go through the same path: Elena schedules a batched update, then runs the <a href="/pr-preview/pr-15/components/lifecycle">update cycle</a>. Only the parts of the DOM that changed are <a href="#how-the-dom-is-updated">updated</a>.</p><h2 id="how-prop-changes-are-detected" tabindex="-1">How prop changes are detected <a class="header-anchor" href="#how-prop-changes-are-detected" aria-label="Permalink to &quot;How prop changes are detected&quot;">​</a></h2><p>Props listed in <code>static props</code> are backed by JavaScript getters and setters. When you assign a new value, the setter compares it to the current value and schedules a re-render if it changed:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// This will trigger an update</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.variant </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;primary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// This does not: the value is the same as above</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.variant </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;primary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>Elena uses strict equality (<code>===</code>) to compare values. If the new value is the same reference as the old one, no render is scheduled.</p><h3 id="reflected-vs-non-reflected-props" tabindex="-1">Reflected vs non-reflected props <a class="header-anchor" href="#reflected-vs-non-reflected-props" aria-label="Permalink to &quot;Reflected vs non-reflected props&quot;">​</a></h3><p>By default, props reflect to HTML attributes. When a reflected prop changes, Elena updates the attribute, which triggers <code>attributeChangedCallback()</code>, which schedules the update. Non-reflected props (declared with <code>{ name, reflect: false }</code>) skip the attribute and schedule the update directly from the setter.</p><h2 id="batched-updates" tabindex="-1">Batched updates <a class="header-anchor" href="#batched-updates" aria-label="Permalink to &quot;Batched updates&quot;">​</a></h2><p>Elena never renders synchronously in response to a prop change. Instead, it queues a <a href="https://developer.mozilla.org/en-US/docs/Web/API/HTML_DOM_API/Microtask_guide" target="_blank" rel="noreferrer">microtask</a> the first time a change is detected. If more props change before the microtask runs, they are all included in the same update:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// These three changes produce one update, not three</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">button.variant </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;primary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">button.disabled </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">button.text </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Save&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>Because microtasks run before the browser paints, the DOM is updated in time for the next frame. There is no visible flicker between changes.</p><h2 id="what-elena-cannot-detect" tabindex="-1">What Elena cannot detect <a class="header-anchor" href="#what-elena-cannot-detect" aria-label="Permalink to &quot;What Elena cannot detect&quot;">​</a></h2><p>Elena tracks prop changes through setters. If a value is mutated in place without going through the setter, Elena has no way to know it changed.</p><p>This applies to:</p><ul><li><strong>Pushing to an array:</strong> <code>this.items.push(&quot;new&quot;)</code> mutates the existing array. The setter never fires because the array reference stays the same.</li><li><strong>Changing a nested property:</strong> <code>this.user.name = &quot;Alex&quot;</code> mutates the object in place.</li><li><strong>Mutating any object or array</strong> without reassigning the prop.</li></ul><p>In these cases, call <code>requestUpdate()</code> to tell Elena that something changed:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.items.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">push</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;new item&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">requestUpdate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><p>Alternatively, replace the value with a new reference. This goes through the setter and triggers a render automatically:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.items </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.items, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;new item&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>For simple cases, <code>requestUpdate()</code> is fine. For components that update lists or nested data frequently, replacing the value with a new reference is more predictable because it works the same as any other prop change.</p></div><h2 id="the-update-cycle" tabindex="-1">The update cycle <a class="header-anchor" href="#the-update-cycle" aria-label="Permalink to &quot;The update cycle&quot;">​</a></h2><p>Each render follows the same sequence:</p><ol><li><code>willUpdate()</code> runs first, so you can compute derived state before the template evaluates.</li><li><code>render()</code> is called to produce the new template shape.</li><li>Elena updates the DOM using the strategy <a href="#how-the-dom-is-updated">described above</a>.</li><li><code>updated()</code> runs after the DOM is updated.</li></ol><p>On the very first render, <code>firstUpdated()</code> also runs, right before <code>updated()</code>. See <a href="./lifecycle">Lifecycle</a> for the full callback reference.</p><h2 id="waiting-for-a-render" tabindex="-1">Waiting for a render <a class="header-anchor" href="#waiting-for-a-render" aria-label="Permalink to &quot;Waiting for a render&quot;">​</a></h2><p>Use <code>updateComplete</code> to wait for the current render to finish:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.text </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Updated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.updateComplete;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.element.textContent); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;Updated&quot;</span></span></code></pre></div><p>If no render is pending, <code>updateComplete</code> resolves immediately. See <a href="./methods">Methods</a> for more details.</p><h2 id="before-the-first-render" tabindex="-1">Before the first render <a class="header-anchor" href="#before-the-first-render" aria-label="Permalink to &quot;Before the first render&quot;">​</a></h2><p>Props can be set on an element before it connects to the page. Elena stores these values internally, but does not render until <code>connectedCallback()</code> runs. This means you can safely configure a component before adding it to the DOM:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> button</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> document.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">createElement</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;elena-button&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">button.variant </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;primary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">button.text </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Save&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">document.body.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">appendChild</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(button); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// First render happens here</span></span></code></pre></div>`,40)])])}const u=t(n,[["render",h]]);export{k as __pageData,u as default};
